BASE_DIR    = os.path.dirname(os.path.abspath(__file__))
CONFIG_FILE = os.path.join(BASE_DIR, "config.json")

def load_config():
    if os.path.exists(CONFIG_FILE):
        with open(CONFIG_FILE) as f:
            return json.load(f)
    return {}

CONFIG = load_config()

# Env vars take priority (Railway/cloud); config.json is the local fallback
def _cfg(env_key: str, json_key: str, default="") -> str:
    return os.environ.get(env_key) or CONFIG.get(json_key, default)

ANTHROPIC_KEY = _cfg("ANTHROPIC_API_KEY", "anthropic_api_key")
ADMIN_EMAIL   = _cfg("ADMIN_EMAIL",        "admin_email")
SYNC_API_KEY  = _cfg("SYNC_API_KEY",       "sync_api_key")   # shared secret for relayÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂserver calls
PORT          = int(_cfg("PORT", "port", "5001"))

# Persistent paths ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ override with env vars on Railway (point to a mounted volume)
DB_FILE     = _cfg("DATABASE_PATH", "_db_path", os.path.join(BASE_DIR, "jobs.db"))
