    def do_POST(self):
        parsed = urlparse(self.path)
        path   = parsed.path

        # ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ Login ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ
        if path == "/login":
            body = urllib.parse.parse_qs(self.read_body().decode())
            email    = body.get("email", [""])[0]
            password = body.get("password", [""])[0]
            user, err = auth.authenticate(email, password)
            if err:
                html = LOGIN_HTML.replace("{error_block}", error_block(err))
                self.send_html(html)
                return
            token = auth.create_session(user["id"])
            self.send_response(302)
            self.send_header("Set-Cookie", auth.make_session_cookie(token))
            dest = "/dashboard" if user.get("onboarding_complete") else "/onboarding"
            self.send_header("Location", dest)
